THE RISK:
{
 "id": "framework-agreement-foreclosure-large-operators",
 "title": "The declared first buyer (large operators, 40% of spend) is closed by global framework agreements, not by competition",
 "narrative": "The venture's stated go-to-market is 'sell to large operators first.' But hyperscalers and large colos do not buy rack power in Central Europe — they call off against global, multi-year framework agreements negotiated at HQ with Schneider, Vertiv, Eaton and Legrand. Vertiv's own partner documentation names Equinix, Alibaba, AT&T and Telefonica as direct major customers. A CE entrant in its first 12 months cannot intercept those frameworks locally: vendor qualification cycles at this buyer class run 18–36 months and are gated by approved-vendor lists that open only at framework renewal. The 0.40 buyer cell the whole GTM rests on is not 'hard to win' — for the model's Year-1 window it is contractually unavailable, and the funnel silently treats it as reachable spend.",
 "category": "competitive",
 "targetNodes": [
  "cust.operator-large"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Large operators procure rack PDUs through global/annual framework agreements with the incumbent top vendors — Vertiv's major-customer list (Equinix, Alibaba, AT&T, Telefonica) documents direct HQ-level supply relationships that CE regional teams call off against rather than re-tender",
   "refs": [
    "digest:cust-mix#c9",
    "digest:cr3-vendors#c6",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "propagation",
   "text": "A pre-launch entrant arrives mid-framework: approved-vendor-list slots do not open within its 12-month horizon, and no source in the corpus documents any local discretionary rack-PDU spend at large operators outside frameworks — the channel-structure data is entirely absent, so nothing in the model gates this cell by contract calendar",
   "refs": [
    "profile:Stage",
    "digest:cust-mix#c3",
    "ledger:cust.operator-large"
   ]
  },
  {
   "step": "model-impact",
   "text": "The 0.40 cust.operator-large share flows through SAM/YAM as winnable at the conservative-ramp pace, but the correct treatment for Year 1 is foreclosure: the cell exits the venture's reachable scope entirely, and the YAM built on 'large operators first' is drawn from spend the venture cannot bid on",
   "refs": [
    "ledger:cust.operator-large",
    "ledger:obtainableFactor",
    "profile:followups.primary-buyer"
   ]
  }
 ],
 "whyMissable": "The ledger expresses buyer mix as shares of spend with sensitivity bands — a share looks winnable at any pace, so the team reads 0.40 ± band as market structure, not as a contract calendar. The digest confirms zero sources publish contract-structure data for this channel, so nothing in the evidence base ever forced the question 'is this cell open to us at all in Year 1?'",
 "expectedObviousness": "medium",
 "falsifier": "The venture (or any comparable new entrant) gets onto a hyperscaler's or large CE colo's approved-vendor list and receives a rack-PDU purchase order within a 12-month window — or documented evidence that CE site teams hold local discretionary PDU budgets outside global frameworks.",
 "likelihood": {
  "value": 0.5,
  "rationale": "Direct global supply relationships between top PDU vendors and named large operators are documented (Vertiv partner materials); framework/AVL procurement is the standard mechanism at this buyer class, though some operators do run open regional RFQs for second-sourcing [evidence revision: The two load-bearing premises — documented HQ-level global supply relationships between incumbents and named large operators, and slow/gated AVL onboarding — are corroborated, raising confidence in the core foreclosure mechanism. But the specific 18–36 month qualification figure is overstated relative to the evidence (weeks-to-months for onboarding), and the OFCI model shows owners can and do procure equipment directly outside a single-vendor framework, which weakens the claim of total Year-1 contractual unavailability. Net effect: a modest upward revision from 0.45 to 0.50, bounded because absence of CE-specific discretionary-budget data leaves the propagation step partly unverified.]",
  "basis": "evidence",
  "revisedFrom": 0.45
 },
 "perturbation": [
  {
   "nodeId": "cust.operator-large",
   "op": "exclude",
   "note": "Large-operator cell foreclosed by framework agreements for the Year-1 window — removed from reachable scope, not merely shrunk"
  }
 ],
 "indicators": [
  {
   "signal": "Vendor-qualification prerequisites in large-operator RFQs (existing global supply agreement or AVL membership required to bid)",
   "where": "Equinix / Digital Realty / NTT EMEA supplier-onboarding portals and CE colo fit-out tender documents",
   "threshold": "≥3 of first 5 large-operator opportunities disqualify at vendor-list stage before any technical evaluation",
   "updates": "increases"
  },
  {
   "signal": "Incumbent commentary on multi-year hyperscale/colo supply agreements and backlog for rack power",
   "where": "Schneider Electric and Vertiv quarterly earnings calls, order-backlog and framework-win discussion",
   "threshold": "Explicit reference to multi-year rack-power supply commitments covering European capacity additions",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Interview 3 CE large-operator procurement leads specifically on framework end-dates, second-source policies and local discretionary spend — establishing whether and when the cell opens",
   "type": "information",
   "voiNodeId": "cust.operator-large",
   "note": "Converts the buyer-mix node's biggest cell from 'assumed reachable' to a dated market-entry calendar"
  },
  {
   "action": "Re-sequence GTM to mid/enterprise operators and integrators for Year 1, treating large operators as a Year-2/3 qualification track timed to framework renewals",
   "type": "strategic",
   "voiNodeId": null,
   "note": "Aligns the ramp with the cells that are actually open mid-cycle"
  },
  {
   "action": "Pursue formal second-source qualification slots, which many framework agreements reserve for supply-resilience reasons",
   "type": "contractual",
   "voiNodeId": null,
   "note": "Second-source status is the only contractual door into a framework mid-term"
  }
 ],
 "evidenceStatus": "corroborated",
 "evidence": [
  {
   "title": "Vertiv EMEA Service Partner Programmes / Corporate Fact Sheet — Major Customers",
   "sourceType": "industry-report",
   "publisher": "Vertiv",
   "date": null,
   "excerpt": "MAJOR CUSTOMERS: Alibaba, Alstom, America Movil, AT&T, China Mobile, Equinix, Ericsson, Reliance, Siemens, Telefonica, Tencent, Verizon and Vodafone — supported by a global, well-established footprint and supply-chain network.",
   "url": "https://www.vertiv.com/4ad20e/globalassets/documents/brochures/vertiv-service-partner-programs-br-en-emea.pdf",
   "attached": true
  },
  {
   "title": "Where Data Center Cooling Projects Really Get Delayed — Supplier Onboarding",
   "sourceType": "industry-report",
   "publisher": "Enercon Power",
   "date": "2026-03-11",
   "excerpt": "Adding a new manufacturer to your approved vendor list is not a fast process... facility audits, quality management system reviews, cybersecurity documentation, insurance verification, NDA execution... this sequence can consume four to twelve weeks before a single panel is quoted.",
   "url": "https://www.enerconpower.com/post/where-data-center-cooling-projects-really-get-delayed",
   "attached": true
  },
  {
   "title": "OFCI vs CFCI: Data Center Equipment Guide",
   "sourceType": "industry-report",
   "publisher": "iRecruit",
   "date": "2026-06-10",
   "excerpt": "OFCI: The owner buys critical equipment (e.g., generators, switchgear) and the contractor installs it... Greater control over long-lead procurement, cost transparency, and bulk purchasing for standardization.",
   "url": "https://www.irecruit.co/insights/ofci-vs-cfci-procurement-owner-vs-contractor-furnished-equipment-data-centers",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.vertiv.com/4ad20e/globalassets/documents/brochures/vertiv-service-partner-programs-br-en-emea.pdf",
   "stance": "supports",
   "quote": "MAJOR CUSTOMERS\nAlibaba, Alstom, America \nMovil, AT&T, China Mobile, \nEquinix, Ericsson, Reliance, \nSiemens, Telefonica, Tencent, \nVerizon and Vodafone"
  },
  {
   "url": "https://www.vertiv.com/495b0e/globalassets/content---assets-2025/documents/vertiv-telefonica_marketing-thought-leadership-case-study_emea-english.pdf",
   "stance": "supports",
   "quote": "Vertiv and the Telefónica Group have maintained a strong, multi-year partnership across Spain and Latin America, \ndeploying energy-efficient critical infrastructure solutions."
  },
  {
   "url": "https://www.vertiv.com/en-emea/about/news-and-insights/news-releases/telefonica-renews-collaboration-agreement/",
   "stance": "supports",
   "quote": "Telefónica Renews Collaboration Agreement with Vertiv to Reduce Energy Consumption and Carbon Footprint at Telefónica Locations in Spain"
  },
  {
   "url": "https://www.enerconpower.com/post/where-data-center-cooling-projects-really-get-delayed",
   "stance": "supports",
   "quote": "Adding a new manufacturer to your approved vendor list is not a fast process. For data center infrastructure, the requirements are more demanding than most industries: facility audits, quality management system reviews, cybersecurity documentation, insurance verification, NDA execution, and compliance checks specific to each hyperscaler or owner's requirements."
  },
  {
   "url": "https://www.aicloudpartners.com/guides/supplierweb-onboarding-guide.html",
   "stance": "supports",
   "quote": "the 3–6 month process that blocks partners who discover it too late"
  },
  {
   "url": "https://www.irecruit.co/insights/ofci-vs-cfci-procurement-owner-vs-contractor-furnished-equipment-data-centers",
   "stance": "contradicts",
   "quote": "OFCI: The owner buys critical equipment (e.g., generators, switchgear) and the contractor installs it."
  },
  {
   "url": "https://www.newsunn.com/bulk-sourcing-basic-pdus-a-guide-for-it-procurement-managers/",
   "stance": "silent",
   "quote": "For large rollouts, a basic PDU can look like a commodity item, but procurement decisions at volume have real cost, compatibility, and reliability implications."
  }
 ]
}

